local CurrentActivityList = {}
local PlayerDataCache = {}
local PayFunction = {}

local function savePlayerData(userId)
    local cache = PlayerDataCache[tostring(userId)]
    if not cache then
        return
    end
    PlayerDataCache[tostring(userId)] = nil
    DBManager:savePlayerData(userId, "CommonActivityData", cache, true)
end

local function isInTimeRange(startTime, endTime)
    if endTime == -1 then
        return true
    end
    local nowTime = os.time(os.date("*t"))
    if nowTime >= startTime and nowTime < endTime then
        return true
    end
    return false
end

local function isHasActivity(activityId)
    for _, activity in pairs(CurrentActivityList) do
        if activity.id == tonumber(activityId) then
            return true, activity
        end
    end
    return false, nil
end

local function LuckyTurntableCalculateWeights(rewardGroup, luckyValue)
    local luckyWeights = LuckyValueConfig:getWeightByLuckyValue(luckyValue)
    ---读取玩家幸运值，改变大奖权重
    local rewardMap = {}
    local weights = 0
    for index, item in pairs(rewardGroup) do
        if item.isGrandPrize == true then
            weights = weights + item.weights + luckyWeights
        else
            weights = weights + item.weights
        end
        local info = { rewardId = index, reward = item.reward, isGrandPrize = item.isGrandPrize, weights = weights }

        table.insert(rewardMap, info)
    end

    local randomResult = math.random(weights)
    local endResult = 0
    local result
    for _, reward in pairs(rewardMap) do
        endResult = endResult + reward.weights
        if randomResult < endResult then
            result = reward
            break
        end
    end
    return result
end

local function receiveReward(player, reward)
    if reward.type == "CommonRewardPool" then
        return CommonActivity:onOpenCommonRewardPool(player, reward.realId)
    end
    if reward.compensate == 0 then
        CommonReceiveRewardEvent:invoke(player, reward.type, reward.realId, reward.num)
        return reward
    end
    local receiveRecord = PlayerDataCache[tostring(player.userId)].receiveRecord
    if receiveRecord[tostring(reward.rewardId)] == nil then
        CommonReceiveRewardEvent:invoke(player, reward.type, reward.realId, reward.num)
        receiveRecord[tostring(reward.rewardId)] = true
        return reward
    else
        local compensateReward = CommonActivityRewardConfig:getRewardById(reward.compensate)
        if not compensateReward then
            LogUtil.log("[CommonActivity] [receiveReward] Not Compensate Reward, RewardId:", reward.rewardId, LogUtil.LogLevel.Error)
            CommonReceiveRewardEvent:invoke(player, reward.type, reward.realId, reward.num)
            return reward
        else
            return receiveReward(player, compensateReward)
        end
    end
end

local function receiveRewardByGroupId(player, groupId)
    local group = CommonActivityRewardConfig:getRewardGroupById(groupId)
    local rewardIds = {}
    for _, item in pairs(group or {}) do
        local reward = receiveReward(player, item.reward)
        table.insert(rewardIds, reward.rewardId)
    end
    return rewardIds
end

function CommonActivity:registerPayFunction(coinId, func)
    PayFunction[coinId] = func
end

function CommonActivity:payMoney(player, uniqueId, coinId, price, successCallback)
    if coinId <= 3 then
        PayHelper.payMoney(player, uniqueId, coinId, price, successCallback)
    else
        local func = PayFunction[coinId]
        if not func then
            return
        end
        if func(player, uniqueId, coinId, price) then
            successCallback()
        end
    end
end

function CommonActivity:init()
    CurrentActivityList = {}
    local config = CommonActivityConfig:getConfigList()
    for _, activity in pairs(config) do
        if isInTimeRange(activity.startTime, activity.endTime) then
            ---活动中
            self:addActivity(activity)
        else
            if activity.startTime ~= 0 and activity.startTime > os.time() then
                ---活动还没开始
                LuaTimer:schedule(function()
                    self:addActivity(activity)
                end, (activity.startTime - os.time() + 1) * 1000)
            end
        end
    end
    if #CurrentActivityList > 0 then
        DBManager:addMustLoadSubKey("CommonActivityData")
    end

    CommonDataEvents:registerCallBack("MustLotteryDelete", function(userId, data)
        local player = PlayerManager:getPlayerByUserId(userId)
        if not player then
            return
        end
        CommonActivity:onMustLotteryDelete(player, data)
    end, JsonBuilderProcessor)

    CommonDataEvents:registerCallBack("MustLotteryDoLottery", function(userId, data)
        local player = PlayerManager:getPlayerByUserId(userId)
        if not player then
            return
        end
        CommonActivity:onMustLotteryDoLottery(player, data)
    end, JsonBuilderProcessor)

    CommonDataEvents:registerCallBack("LuckyLottery", function(userId, data)
        local player = PlayerManager:getPlayerByUserId(userId)
        if not player then
            return
        end
        CommonActivity:onLuckyLottery(player, data)
    end, JsonBuilderProcessor)

    CommonDataEvents:registerCallBack("CommonActivityOpenChest", function(userId, data)
        local player = PlayerManager:getPlayerByUserId(userId)
        if not player then
            return
        end
        CommonActivity:onOpenChest(player, data)
    end, JsonBuilderProcessor)
end

function CommonActivity:checkCanReceiveReward(player, rewardNum)
    if player:checkCanReceiveCommonReward(rewardNum) == false then
        return false
    end
    return true
end

function CommonActivity:getChestGroupEndTime(startTime, refreshTime)
    return (os.time() - ((os.time() - startTime) % refreshTime)) + refreshTime
end

function CommonActivity:addActivity(activity)
    table.insert(CurrentActivityList, activity)
    if activity.endTime ~= -1 then
        LuaTimer:schedule(function()
            self:removeActivity(activity)
        end, (activity.endTime - os.time()) * 1000)
    end
    local chestGroup = CommonActivityChestConfig:getChestGroupById(activity.chestGroupId)
    if chestGroup and chestGroup.refreshTime ~= -1 then
        local chestEndTime = self:getChestGroupEndTime(activity.startTime, chestGroup.refreshTime)
        activity.chestTimer = LuaTimer:schedule(function()
            for _, cache in pairs(PlayerDataCache) do
                local data = cache.activity[tostring(activity.id)]
                if data then
                    data.lotteryTimes = 0
                    data.getChest = ""
                end
            end
            local packet = { activityId = activity.id, lotteryTimes = 0, getChest = "" }
            PacketSender:broadCastLuaCommonData("CommonActivityRefreshChest", json.encode(packet))
        end, (chestEndTime - os.time()) * 1000, chestGroup.refreshTime * 1000)
    end
    if TableUtil.getTableSize(PlayerDataCache) == 0 then
        return
    end
    local data = { id = activity.id }
    if activity.endTime > 0 then
        data.lastTime = activity.endTime - os.time()
    else
        data.lastTime = activity.endTime or -1
    end
    local init = CommonActivity:initDataByType(activity.type)
    for _, cache in pairs(PlayerDataCache) do
        cache.activity[tostring(activity.id)] = init
    end
    for key, value in pairs(init) do
        data[key] = value
    end
    PacketSender:broadCastLuaCommonData("AddCommonActivity", json.encode(data))
end

function CommonActivity:removeActivity(activity)
    LuaTimer:cancel(activity.chestTimer)
    TableUtil.tableRemove(CurrentActivityList, activity)
    local data = { activityId = activity.id }
    PacketSender:broadCastLuaCommonData("RemoveCommonActivity", json.encode(data))
end

function CommonActivity:getPlayerDBData(player)
    DBManager:getPlayerData(player.userId, "CommonActivityData", function(userId, _, data)
        if data.__first then
            data.activity = {}
            data.receiveRecord = {}
        end
        PlayerDataCache[tostring(userId)] = data
        local result = {}
        for _, activity in pairs(CurrentActivityList) do
            local item = { id = activity.id }
            if activity.endTime > 0 then
                item.lastTime = activity.endTime - os.time()
            else
                item.lastTime = activity.endTime or -1
            end
            local cache = data.activity[tostring(activity.id)]
            if not cache then
                local init = CommonActivity:initDataByType(activity.type)
                data.activity[tostring(activity.id)] = init
                cache = init
            else
                ---升级数据库数据
                local init = CommonActivity:initDataByType(activity.type)
                ---更新减少字段时
                for key, _ in pairs(cache) do
                    if not init[key] then
                        cache[key] = nil
                    end
                end
                ---更新增加字段时
                for key, value in pairs(init) do
                    if not cache[key] then
                        cache[key] = value
                    end
                end
            end
            local chestGroup = CommonActivityChestConfig:getChestGroupById(activity.chestGroupId)
            if chestGroup and chestGroup.refreshTime ~= -1 then
                local chestEndTime = self:getChestGroupEndTime(activity.startTime, chestGroup.refreshTime)
                if chestEndTime ~= cache.chestEndTime then
                    cache.chestEndTime = chestEndTime
                    cache.lotteryTimes = 0
                    cache.getChest = ""
                end
            end
            for key, value in pairs(cache) do
                item[key] = value
            end
            table.insert(result, item)
        end
        PacketSender:sendLuaCommonData(player.rakssid, "SyncCommonActivity", json.encode(result))
        ---清除过期活动的数据缓存
        for activityId, _ in pairs(data.activity) do
            if not isHasActivity(activityId) then
                data.activity[activityId] = nil
            end
        end
    end)
end

function CommonActivity:onPlayerReady(player)
    if #CurrentActivityList == 0 then
        return
    end
    CommonActivity:getPlayerDBData(player)
end

function CommonActivity:onPlayerLogout(player)
    savePlayerData(player.userId)
end

