    if not data then
        return
    end
    local cache = data.activity[tostring(deleteData.activityId)]
    if not cache then
        return
    end
    cache.deleteSeq = deleteData.deleteSeq
    PacketSender:sendLuaCommonData(player.rakssid, "MustLotteryDelete", json.encode(deleteData))
